import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"神躯化剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/神躯化剑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/神躯化剑.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/神躯化剑.md"};function d(l,e,_,i,p,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"神躯化剑",tabindex:"-1"},[n("神躯化剑 "),r("a",{class:"header-anchor",href:"#神躯化剑","aria-label":'Permalink to "神躯化剑"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),s('<h1 id="神躯化剑-1" tabindex="-1">神躯化剑 <a class="header-anchor" href="#神躯化剑-1" aria-label="Permalink to &quot;神躯化剑&quot;">​</a></h1><p>神躯化剑<br> 本质：神话本质<br> 价格：A+4000<br> 分类：重剑<br> 体积：4<br> 武器伤害：28L 附带2点附加成功<br> 武器属性：【重型武器】【双手】<br> 描述：<br> 本该永恒不死的神祇──<br> 从神祇的遗体诞生的剑。<br> 人们从中看见了不同的含义──<br> 重罪、毁灭、时代的终结，<br> 也或者是开端。<br> 效果：<br> 【弑神之罪】：这柄开有数个空洞，材质难辨的剑，乃是由神明的遗骸所化。一尊神的统治从此终结，新的王者自此登上王座。<br> 只要持有这柄剑，你便被弑杀神明的罪业所纠缠，无法受到任何与“黄金律法”相关的增益效果，同时与黄金律法类似阵营的强调“秩序”，“永恒不变，“完美”等理念的神祇及其信徒的能力所带来的增益效果你也无法享受（具体由GM进行裁定）。<br> 然而也正因毁灭了旧有的神，这柄剑才能够象征着新生的王者。只要持有这柄剑，你就具有A级别的针对命运来源效果的免疫。<br> 仅在对神进行攻击时（这里的神的定义为起码有一万人以上将其作为神明供奉的超自然存在，或者是能够掌握所在世界的世界规则一部分的超自然生物），每轮一次，这把剑进行的攻击的伤害提升一倍，并且附带S级的针对复活能力的免疫效果。<br> 具有A等级以上的魔幻本质侦测等级的存在能够看出，这柄剑是由神明的尸身所化，以及其所具有的象征意义，这可能会影响一些特定世界观中的NPC对你的看法。<br> 【神力剑气】：消耗一个迅捷动作和1点意志力，你可以令神躯化剑上燃起金色的光辉，持续一轮。金色的光辉，是象征旧时律法的神明的力量。<br> 在剑上燃起金色的光辉过后，神躯化剑进行挥砍和穿刺的威力都会增强。在施展神力剑气的生效时间的这一轮内，你所进行的所有攻击将附带10DP的祝福加值，并且可以选择改为造成正能量伤害而非劈砍伤害，并且在这一轮内，你的攻击还会具有【湮灭】特性。<br> 同时你可以通过斩击让承载着律法力量的剑气飞射而出，这视为在神力剑气生效期间，你进行的白刃攻击的射程提升140米。<br> 【黄金波动】：将剑身寄宿旧时的黄金，接着释放的战技。黄金波动会朝前方扇状大幅扩散，横扫所有敌人。<br> 同时【黄金波动】也是《艾尔登法环》世界观中的战技之一，所以也可以享受褪色者血统中的【战士禀赋】的dp加值，并且可以使用其AP来转化施展所需要的的动作。<br> 在启动了【神力剑气】的状态下，消耗一个整轮动作和4点意志力，你可以释放黄金波动。<br> 黄金波动是一次白刃攻击，如常进行检定。在具有【神力剑气】的效果的基础上，在释放黄金波动时，你从【神力剑气】中获得的射程提升效果给你带来的增益变为三倍（即提升420米射程），并且你这次攻击必须造成正能量伤害。<br> 这次攻击将会对以你这次白刃攻击的射程为半径的扇形范围内的所有敌人造成伤害，对手需要以反射豁免来应对这次攻击。<br> 黄金的波动宛如浪涛，从空间中涌起，能够穿透物质乃至时空的阻拦，命中敌手。黄金波动具有A级别的【传送攻击】但是来源并非是时空来源，而是祝福来源。<br> 由于黄金波动宏大的威力，这次攻击骰的出目将会变为1.5倍，同时只要这次攻击确实地造成了伤害，那么所有被造成伤害的对象还需要进行一次强韧豁免来对抗你的攻击出目，如果失败，则会被律法的力量所击溃，陷入持续一轮的A级别的祝福来源的震慑状态，并且你还可以用一个自由动作在这次攻击中结合一次摔绊。<br> 由于黄金波动是宛如波动一般掠过敌人，因而这次攻击无法通过任何方式造成冲击点数。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const A=a(o,[["render",d]]);export{f as __pageData,A as default};
